<template>
    <div class="page">
        <div class="nav flex" v-loading="loading">
            <div class="tree">
                <el-tree
                    :data="treeData"
                    :props="defaultProps"
                    @node-click="handleNodeClick"
                    :expand-on-click-node="false"
                >
                </el-tree>
            </div>
            <div class="setImg" v-if="showForm">
                <el-form ref="form" :model="form" label-width="150px" style="margin-top: 20px">
                    <el-form-item label="分类名" label-width="150px">
                        <el-input v-model="form.className" readonly style="width: 300px"></el-input>
                    </el-form-item>
                    <el-form-item label="分类图片" label-width="150px">
                        <el-upload
                            class="avatar-uploader"
                            action="/upload"
                            :show-file-list="false"
                            :on-success="handleAvatarSuccess"
                            :before-upload="beforeAvatarUpload"
                            name="image"
                        >
                            <img v-if="form.imageUrl" :src="form.imageUrl" class="avatar">
                            <i v-else class="el-icon-plus avatar-uploader-icon"></i>
                        </el-upload>
                    </el-form-item>
                    
                </el-form>
            </div>
        </div>
    </div>
</template>
  
<script>
import mercariClass from './mercariClass'
import yahooClass from './yahooClass'

import {fenleiupdata, fenleiselect} from "@/http/api"

export default {
    data(){
        return {
            treeData: [],
            defaultProps: {
                children: 'children',
                label: 'cname'
            },
            currentNode: {},
            
            form: {
                className: '',
                imageUrl: '',
            },
            loading: false,
            showForm: false,
        }
    },
    created(){
        // console.log('mercariClass', mercariClass)
        // this.treeData = JSON.parse(localStorage.getItem('mercariClass'))
        this.getClasses()
    },
    methods: {
        async getClasses(){
            this.loading = true
            const res = await fenleiselect()
            const {code, data, msg} = res
            if(code === 0){
                console.log()
                const classes = JSON.parse(data.content)
                this.treeData = classes.mercariClass
            }else{
                this.$message.error(msg)
            }
            this.loading = false
        },
        handleNodeClick(data, node, comp) {
            if(node.level === 2){
                this.showForm = true
                this.currentNode = data
                this.form.className = data.cname || ''
                this.form.imageUrl = data.imageUrl || ''
            }else{
                this.showForm = false
            }
        },
        async handleAvatarSuccess(res){
            this.loading = true
            console.log('res', res)
            this.form.imageUrl = res.data
            this.currentNode.imageUrl = res.data
            localStorage.setItem('mercariClass', JSON.stringify(this.treeData))
            const params = {
                content: JSON.stringify({
                    mercariClass: this.treeData,
                    yahooClass: []
                })
            }
            const fenlei_res = await fenleiupdata(params)
            const {code, data, msg} = fenlei_res
            if(code === 0){
                this.$message.success('操作成功')
            }else{
                this.$message.error(msg)
            }
            this.loading = false

        },
        beforeAvatarUpload(file) {
            console.log(file.type)
            const isJPG = file.type === 'image/jpeg' || file.type === 'image/png';
            const isLt2M = file.size / 1024 / 1024 < 2;

            if (!isJPG) {
                this.$message.error('上传头像图片只能是 JPG 或 PNG 格式!');
            }
            if (!isLt2M) {
                this.$message.error('上传头像图片大小不能超过 2MB!');
            }
            return isJPG && isLt2M;
        }
    }
}
</script>

<style>
  .avatar-uploader .el-upload {
    border: 1px dashed #d9d9d9;
    border-radius: 6px;
    cursor: pointer;
    position: relative;
    overflow: hidden;
  }
  .avatar-uploader .el-upload:hover {
    border-color: #409EFF;
  }
  .avatar-uploader-icon {
    font-size: 28px;
    color: #8c939d;
    width: 178px;
    height: 178px;
    line-height: 178px;
    text-align: center;
  }
  .avatar {
    width: 178px;
    height: 178px;
    display: block;
  }
</style>
  
<style lang="scss" scoped>
.tree{
    width: 300px;
}
</style>
  